CREATE TABLE IF NOT EXISTS "StockItem" (id TEXT PRIMARY KEY, sku TEXT NOT NULL, "warehouseId" TEXT NOT NULL, quantity INTEGER DEFAULT 0, "reorderPoint" INTEGER DEFAULT 0, "reservedQty" INTEGER DEFAULT 0, unit TEXT DEFAULT 'units', "createdAt" TIMESTAMP DEFAULT NOW(), "updatedAt" TIMESTAMP DEFAULT NOW(), UNIQUE(sku, "warehouseId"));
CREATE TABLE IF NOT EXISTS "Warehouse" (id TEXT PRIMARY KEY, name TEXT NOT NULL, city TEXT, state TEXT, active BOOLEAN DEFAULT true);
CREATE TABLE IF NOT EXISTS "StockMovement" (id UUID DEFAULT gen_random_uuid() PRIMARY KEY, sku TEXT NOT NULL, "warehouseId" TEXT NOT NULL, type TEXT NOT NULL, quantity INTEGER NOT NULL, "referenceId" TEXT, reason TEXT, "createdAt" TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS "Order" (id TEXT PRIMARY KEY, "customerId" TEXT NOT NULL, channel TEXT DEFAULT 'manual', status TEXT DEFAULT 'draft', "totalAmount" FLOAT DEFAULT 0, "shippingAddress" JSONB, "createdAt" TIMESTAMP DEFAULT NOW(), "updatedAt" TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS "OrderLine" (id UUID DEFAULT gen_random_uuid() PRIMARY KEY, "orderId" TEXT NOT NULL REFERENCES "Order"(id), sku TEXT NOT NULL, name TEXT, quantity INTEGER DEFAULT 1, "unitPrice" FLOAT DEFAULT 0);
CREATE TABLE IF NOT EXISTS "Product" (id TEXT PRIMARY KEY, sku TEXT UNIQUE NOT NULL, name TEXT NOT NULL, category TEXT, status TEXT DEFAULT 'draft', revision TEXT DEFAULT '1.0', description TEXT);
CREATE TABLE IF NOT EXISTS "ProductCard" (id TEXT PRIMARY KEY, "productId" TEXT NOT NULL UNIQUE, name TEXT NOT NULL, "categoryId" TEXT, status TEXT DEFAULT 'draft', description TEXT, attributes JSONB DEFAULT '{}', variants JSONB DEFAULT '[]');
CREATE TABLE IF NOT EXISTS "Customer" (id TEXT PRIMARY KEY, name TEXT, email TEXT UNIQUE, phone TEXT, document TEXT, tier TEXT DEFAULT 'bronze', "createdAt" TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS "PriceListItem" (id TEXT PRIMARY KEY, "productId" TEXT NOT NULL UNIQUE, price FLOAT DEFAULT 0, cost FLOAT DEFAULT 0, active BOOLEAN DEFAULT true);
CREATE TABLE IF NOT EXISTS "EpisodicEvent" (id TEXT PRIMARY KEY DEFAULT gen_random_uuid()::TEXT, "agentId" TEXT NOT NULL, type TEXT NOT NULL, data JSONB DEFAULT '{}', timestamp TIMESTAMP DEFAULT NOW());
